创建表删除表更改属性 <pre><code>    CREATE TABLE takes (      
        ID              varchar(5)  not null,        
        course_id       varchar(8),      
        sec_id          varchar(8),        
        semester        varchar(6),        
        year            numeric(4,0),        
        grade           varchar(2),        
        primary key (ID, course_id, sec_id, semester, year),        
        foreign key (ID) references  student,        
        foreign key (course_id, sec_id, semester, year) references section 
    );
</code></pre> <pre><code>    # 删除表和内容
    DROP TABLE takes;
    # 删除内容
    DELETE FROM takes;
</code></pre> <pre><code>    # 增加列
    ALTER TAABLE r ADD A D;
    # 删除列
    ALTER TABLE r DROP A;
</code></pre>
